1	// Static tests asserting the distribution-proof transcript structure and
2	// verify-appimage.sh integrity — no FUSE mount, no VM required.
3	//
4	// Transcripts may carry any of three valid STATUS values:
5	//   STATUS: ok                    (full VM run succeeded)
6	//   STATUS: skipped:tools-missing (build host lacks linuxdeploy/appimagetool)
7	//   STATUS: pending VM run        (placeholder until VM run is executed in S02)
8	// All three are accepted here; only structural completeness is enforced.
9	//
10	// Supported distros (M011): Debian 13, Ubuntu 26.04, Fedora 44, CachyOS
11	
12	use std::fs;
13	use std::os::unix::fs::PermissionsExt;
14	use std::path::Path;
15	
16	fn project_root() -> std::path::PathBuf {
17	    Path::new(env!("CARGO_MANIFEST_DIR")).to_path_buf()
18	}
19	
20	fn read_file(rel: &str) -> String {
21	    let path = project_root().join(rel);
22	    fs::read_to_string(&path).unwrap_or_else(|e| panic!("cannot read {rel}: {e}"))
23	}
24	
25	const REQUIRED_FIELDS: &[&str] = &[
26	    "STATUS:",
27	    "DISTRO:",
28	    "KERNEL:",
29	    "SIZE_BYTES:",
30	    "SHA256:",
31	    "EXIT_CODE:",
32	    "VERSION_OUTPUT:",
33	];
34	
35	const VALID_STATUSES: &[&str] = &[
36	    "STATUS: ok",
37	    "STATUS: skipped:tools-missing",
38	    "STATUS: pending VM run",
39	];
40	
41	fn assert_transcript(rel: &str) {
42	    let content = read_file(rel);
43	    for field in REQUIRED_FIELDS {
44	        assert!(
45	            content.contains(field),
46	            "transcript {rel} is missing required field '{field}'"
47	        );
48	    }
49	    let has_valid_status = VALID_STATUSES.iter().any(|s| content.contains(s));
50	    assert!(
51	        has_valid_status,
52	        "transcript {rel} has no recognized STATUS line; accepted values: {:?}",
53	        VALID_STATUSES
54	    );
55	}
56	
