77	#[test]
78	fn verify_appimage_sh_exists_and_is_executable() {
79	    let path = project_root().join("scripts/verify-appimage.sh");
80	    assert!(
81	        path.exists(),
82	        "scripts/verify-appimage.sh must exist"
83	    );
84	    let meta = fs::metadata(&path).expect("cannot stat scripts/verify-appimage.sh");
85	    let mode = meta.permissions().mode();
86	    assert!(
87	        mode & 0o111 != 0,
88	        "scripts/verify-appimage.sh must be executable (mode={mode:#o})"
89	    );
90	}
91	
92	#[test]
93	fn verify_appimage_sh_contains_status_emitter() {
94	    let src = read_file("scripts/verify-appimage.sh");
95	    assert!(
96	        src.contains("STATUS:"),
97	        "scripts/verify-appimage.sh must contain a STATUS: line emitter"
98	    );
99	    // The script writes the structured transcript unconditionally — even on failure.
100	    assert!(
101	        src.contains("echo \"STATUS:"),
102	        "scripts/verify-appimage.sh must emit STATUS via echo"
103	    );
104	}
